    <div>
        <input type="checkbox" id="checkbox1"> Checkbox 1<br>
        <input type="checkbox" id="checkbox2"> Checkbox 2<br>
        <input type="checkbox" id="checkbox3"> Checkbox 3<br>
    </div>
    <button id="saveButton">Save</button>

    <script>
        // Function to select all checkboxes
        function selectAllCheckboxes() {
            const checkboxes = document.querySelectorAll('input[type="checkbox"]');
            checkboxes.forEach(checkbox => checkbox.checked = true);
        }

        // Function to trigger the save button click
        function triggerSaveButton() {
            const saveButton = document.getElementById('saveButton');
            if (saveButton) {
                saveButton.click();
            }
        }

        // Add an event listener to the "Select All" button
        document.addEventListener('DOMContentLoaded', () => {
            const selectAllButton = document.createElement('button');
            selectAllButton.textContent = 'Select All';
            selectAllButton.style.marginTop = '20px';

            selectAllButton.addEventListener('click', () => {
                selectAllCheckboxes();
                triggerSaveButton();
            });

            document.body.appendChild(selectAllButton);
        });
    </script>
</body>
</html>
